var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…쿨럭…","JPN":"……ゲホッ……","ENG":"…*Cough…*","TWN":"…咳…"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그 닳고 닳은 몸뚱아리로 언제까지 버틸 셈이지?","JPN":"その擦り切れた体でいつまで耐えるつもりだ？","ENG":"How long do you plan to last in that worn-out husk of a body?","TWN":"你那破舊的身軀，還能撐到什麼時候？"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 그 검에 피를 먹여라. 그리고 마지막 힘을 비틀어 짜내어, 본좌에게 맞서 보거라.","JPN":"さっそくその剣に血を飲ませるのだ。そして最後の力を振り絞り、吾輩に立ち向かってみせよ。","ENG":"Feed that sword your blood. Wring out the last of your strength and come challenge me.","TWN":"快點用血餵那把劍。然後榨乾最後的力量，來對抗本座。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 힘을… 네놈에게 쓰는 일은 없을 거다.","JPN":"この力を……貴様に使うことはない。","ENG":"I won't… waste this power on the likes of you.","TWN":"我絕不會將這份力量，用在你身上。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"막상 닥쳐오니 희생이 두려운가? 아니면 그것이 무의미함을 깨달았나?","JPN":"いざとなると犠牲が怖くなったか？　それとも、それが無意味であることにようやく気づいたか？","ENG":"So when the moment of sacrifice arrives, you're now afraid? Or have you finally realized it's all meaningless?","TWN":"面對死亡，你感到恐懼了嗎？還是你意識到這是毫無意義的？"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"네 몸에 흐르는 피는 본좌의 작은 조각에 지나지 않으니.","JPN":"お前の体に流れる血は吾輩のほんの一部に過ぎん。","ENG":"The blood flowing through you is merely a fragment of me.","TWN":"你身體裡流淌的血，不過是本座的一小部分。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그 힘으론 결코 본좌를 이기지 못함이라.","JPN":"その力では決して吾輩に勝つことはできぬだろう。","ENG":"With that, you will never defeat me.","TWN":"那種力量，絕不可能戰勝本座。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 목덜미에… 누군가 베어낸 흔적이 남아 있군.","JPN":"その首……誰かに斬られた跡があるな。","ENG":"That scar on your neck… Someone struck you once, didn't they?","TWN":"你的脖頸上… 還有被什麼人斬過的痕跡。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과거에 숨어 긴 세월을 보냈음에도, 아직 그 상처를 지우지 못한 건가?","JPN":"あれだけの時間を過去に隠れて過ごしていても、その傷跡は消せなかったのか。","ENG":"Even after hiding in the past for so long, you still bear that wound, huh?","TWN":"雖然躲在過去度過了漫長歲月，但還是無法抹去那個傷口嗎？"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Kgh…!","TWN":"咳…！"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG"},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"눈썰미가 좋구나.","JPN":"いい観察力だ。","ENG":"Sharp eyes.","TWN":"你觀察力真好。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"한낱 미물이 배운 재주임에도 그 바라밀 명도라는 것은 매섭기 그지 없더군.","JPN":"取るに足らぬ下等な存在の技とはいえ、あの波羅蜜命刀というものは実に鋭いものであった。","ENG":"For a lowly mortal's technique, that so-called Sword of Paramita cuts deeper than one would expect.","TWN":"一個區區凡人所學的技藝，那個波羅密命刀真是無比鋒利。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"네 선조들이 우릴 죽이려고 억겁의 세월 동안 연마해낸 전승이니 그럴 만도 하지.","JPN":"お前の先祖が我々を討つために億万劫の時をかけて磨き上げた伝承だけはある。","ENG":"Your ancestors honed that style over countless ages to kill us. No wonder it bites.","TWN":"這是你的祖先為了殺死我們，在永恆歲月中磨練出來的傳承，所以當然厲害。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"바라밀 명도… 연화가 명달에게 전수 받았다던?","JPN":"波羅蜜命刀……レンカがアカタツから教わったというあれか。","ENG":"The Sword of Paramita… the one Yeonhwa said she learned from Myeongdal?","TWN":"波羅密命刀… 蓮華從明達那裡繼承的？"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"…그래.","JPN":"……そうだ。","ENG":"…Yes.","TWN":"…沒錯。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"허나, 그 유이한 전승자 둘도 끝내 본좌의 목을 떨어트리진 못했다. 그리고 지금은 이 뱃속으로 들어왔지.","JPN":"されど、その2人の伝承者とて、ついぞ吾輩の首を切り落とせなかった。今やこの腹の中に収まった始末。","ENG":"And yet, even the only two heirs of that art couldn't sever my head. Now they both reside in my belly.","TWN":"然而，那兩個唯一的繼承者，也未能斬下本座的頭顱。現在，他們都進了我的肚子。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"곧 네놈도 같은 처지가 되리라.","JPN":"もうじきお前もやつらと同じ様にしてやろう。","ENG":"Soon, you'll join them.","TWN":"你很快也會是同樣的下場。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그렇군.","JPN":"……そうか。","ENG":"…I see.","TWN":"…原來如此。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"거기에 있었어.","JPN":"そこにいたのか。","ENG":"So that's where you were.","TWN":"在那裡。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"네놈이 절명에 이르러 환시라도 보는 모양이구나.","JPN":"死に時になって、幻でも見ている様子ではないか。","ENG":"You must be hallucinating in your final moments.","TWN":"你是不是快死了，產生幻覺了？"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"말씀하시었던 10년… 아직 안 지났소.","JPN":"仰っていた10年は……まだ経っておらん。","ENG":"The ten years you mentioned… they haven't passed yet.","TWN":"你說的十年… 還沒到。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러니 부디 내 부름에 대답해주시게.","JPN":"だからどうか、某の呼びかけに答えてくれ。","ENG":"So please, answer my call.","TWN":"所以，請回答我的呼喚吧。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"또 무의미하게 맞서려는가.","JPN":"またも無意味な抵抗をするか。","ENG":"Still you insist on fighting, knowing it's meaningless?","TWN":"你又要進行無意義的對抗嗎？"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"그토록 내몰려있음에도 한이 느껴지지 않다니. 네놈은 애초부터 삶에 미련이 없구나.","JPN":"それほど窮地に追い込まれても恨みを抱かないとは。お前、もとより生に未練がなかったのか。","ENG":"Even after being cornered like this, I sense no grudge in you. You've never had any will to cling to life, have you?","TWN":"你被逼到如此絕境，卻沒有任何遺憾。你從一開始就對生命沒有留戀。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"한과 미련은 죽음을 각오한 뒤에나 품는 것…","JPN":"恨みと未練は死を覚悟したうえで抱くもの……","ENG":"Grudge and regret. Those come only after you've accepted death…","TWN":"遺憾和留戀，是為死去做準備時才懷有的情感…"},"stage":{"bg":"CLOSE","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"오늘 네놈에게 내 목을 내어줄 요량은 한 치도 없다.","JPN":"今日貴様に某の首を差し出すつもりは微塵もない。","ENG":"And today, I have no intention of offering you my neck.","TWN":"我今天沒有半點打算，要把我的頭顱交給你。"},"stage":{"bg":"CLOSE","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};